async def execute_initiate_payment(bot: discord.Client, db_handler, params: Dict[str, Any]) -> Dict[str, Any]:
    """Create or resume one admin-triggered payment intent.

    Wallets for initiated payouts must come from wallet_registry keyed by the mentioned Discord
    user. This executor never accepts an LLM-sourced wallet address override.
    """
    params = dict(params or {})
    popped_wallet_address = params.pop('wallet_address', None)
    popped_recipient_wallet = params.pop('recipient_wallet', None)
    if popped_wallet_address not in (None, '') or popped_recipient_wallet not in (None, ''):
        logger.warning(
            "[AdminChat] Ignoring injected wallet fields for initiate_payment: wallet_address=%s recipient_wallet=%s",
            _redact_wallet_address(popped_wallet_address),
            _redact_wallet_address(popped_recipient_wallet),
        )
    try:
        guild_id = int(params.get('guild_id'))
        source_channel_id = int(params.get('source_channel_id'))
        recipient_user_id = int(params.get('recipient_user_id'))
        amount_sol = float(params.get('amount_sol'))
    except (TypeError, ValueError):
        return {"success": False, "error": "guild_id, source_channel_id, recipient_user_id, and amount_sol must be valid"}
    if guild_id <= 0 or source_channel_id <= 0 or recipient_user_id <= 0 or amount_sol <= 0:
        return {"success": False, "error": "guild_id, source_channel_id, recipient_user_id, and amount_sol must be > 0"}
    if not getattr(bot, 'payment_service', None):
        return {"success": False, "error": "payment_service is not configured"}

    existing = db_handler.get_active_intent_for_recipient(guild_id, source_channel_id, recipient_user_id)
    if existing:
        return {"success": True, "duplicate": True, "intent": existing}

def create_payment_request(self, record: Dict, guild_id: Optional[int] = None) -> Optional[Dict]:
    """Insert one payment request row and return the stored record."""
    effective_guild_id = guild_id or record.get('guild_id')
    if effective_guild_id is None:
        logger.error("create_payment_request requires guild_id")
        return None
    if not self._gate_check(effective_guild_id):
        return None
    if not self.supabase:
        return None

    try:
        payload = self._serialize_supabase_value(dict(record))
        payload['guild_id'] = effective_guild_id
        result = self.supabase.table('payment_requests').insert(payload).execute()
        return result.data[0] if result.data else None
    except Exception as e:
        logger.error(f"Error creating payment request: {e}", exc_info=True)
        return None

def get_payment_request(self, payment_id: str, guild_id: Optional[int] = None) -> Optional[Dict]:
    """Fetch one payment request by payment_id."""
    effective_guild_id = guild_id or self._resolve_payment_request_guild_id(payment_id)
    if not self._gate_check(effective_guild_id):
        return None
    if not self.supabase:
        return None

    try:
        result = (
            self.supabase.table('payment_requests')
            .select('*')
            .eq('payment_id', payment_id)
            .eq('guild_id', effective_guild_id)
            .limit(1)
            .execute()
        )
        return result.data[0] if result.data else None
    except Exception as e:
        logger.error(f"Error fetching payment request {payment_id}: {e}", exc_info=True)
        return None

