        result = query.order('created_at', desc=True).limit(limit).execute()
        rows = result.data or []
        if verified_only:
            rows = [row for row in rows if row.get('verified_at')]
        return rows
    except Exception as e:
        logger.error(f"Error listing wallets for guild {guild_id}: {e}", exc_info=True)
        return []

